def fix_indentation(code_block):
    lines = code_block.splitlines()
    fixed_lines = []
    current_indent_level = 0
    INDENT_STEP = 4

    for line in lines:
        stripped_line = line.strip()

        if not stripped_line:
            fixed_lines.append("")
            continue

        # Adjust indentation level for 'else', 'elif', 'except', 'finally'
        # These keywords should align with the start of the block they extend/modify,
        # implying a temporary dedent for themselves.
        if stripped_line.startswith(('elif ', 'else:', 'except ', 'finally:')):
            current_indent_level = max(0, current_indent_level - 1)

        # Apply current indentation to the line
        fixed_lines.append(' ' * (current_indent_level * INDENT_STEP) + stripped_line)

        # Increase indentation level for subsequent lines if the current line ends with a colon
        if stripped_line.endswith(':'):
            current_indent_level += 1

        # Note: This simple heuristic does not automatically dedent when a block ends
        # (e.g., after a 'return' statement or when a loop/conditional block simply finishes)
        # unless an 'elif', 'else', etc. keyword explicitly appears.
        # A more robust solution would require parsing the code or more advanced state tracking.

    return '\n'.join(fixed_lines)

# Example unindented code block
unindented_code = """
def my_function(param1, param2):
if param1 > param2:
print("Param1 is greater")
result = param1 - param2
elif param1 < param2:
print("Param2 is greater")
result = param2 - param1
else:
print("Params are equal")
result = 0
return result

class MyClass:
def __init__(self):
self.value = 10

def get_value(self):
if self.value > 5:
return self.value
else:
return 5
"""

# Fix the indentation and print the result
fixed_code = fix_indentation(unindented_code)
print(fixed_code)
